var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`<color=#ffd34c>캐번디시로부터 수신한 메일입니다.</color>`,JPN:`<color=#ffd34c>キャベンディッシュから受信したメールです。</color>`,ENG:`<color=#ffd34c>A mail arrived from Cavendish.</color>`,TWN:`<color=#ffd34c>來自卡文迪許的郵件。</color>`},stage:{bg:`BLACK`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`코핀 컴퍼니의 작전 진행은 아주 인상적이었습니다, 사장님.`,JPN:`コフィンカンパニーの作戦の進め方はとても印象的でしたよ、社長。`,ENG:`The Coffin Company's operation procedure was very impressive.`,TWN:`科芬公司的戰略部署很令人印象深刻的呀，老闆。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`현장에 동행했던 제 대리인도 호평 일색이더군요.`,JPN:`現場に同行した私の代理人も皆高く評価していました。`,ENG:`My agent who followed you out to the field gave very favorable comments.`,TWN:`跟我同行的代理人也對此讚不絕口。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`상급자의 평가 역시 긍정적입니다. 다음에 다시 함께 일할 기회가 있길 바랍니다.`,JPN:`上司の評価も上々です。またいつか一緒に仕事ができることを願っています。`,ENG:`And our superior also gave a positive assessment. We look forward to working together with you again.`,TWN:`上級的評價也很積極。希望下次一起合作的機會。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`보수는 프론트 베이 시영 부두의 LFHU 252453 컨테이너에 보관해 뒀습니다.`,JPN:`報酬はフロントベイの市営埠頭にある、LFHU252453コンテナに保管してあります。`,ENG:`Your payment is stored in the Container LFHU 252453 located at Front Bay Municipal Pier.`,TWN:`報酬我就放在前灣市營碼頭的LFHU 252453貨櫃裡了。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}}];export{e as default};